/**
 * Tests for posttool/chain-staleness-checker — M168 Phase 3 (#1913).
 *
 * Coverage:
 *   - emits `chain_stale` when `.claude/chain/state.json` is older
 *     than STALE_THRESHOLD_MS and status != 'completed';
 *   - no emit when chain is fresh;
 *   - no emit when status === 'completed';
 *   - rate-limit: second call within RATE_LIMIT_MS skips silently;
 *   - missing chain file = silent success.
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import {
  existsSync,
  mkdirSync,
  mkdtempSync,
  rmSync,
  writeFileSync,
  utimesSync,
} from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

import {
  chainStalenessChecker,
  __internals as chainInternals,
} from '../../posttool/chain-staleness-checker.js';
import { readEventsSince } from '../../lib/event-log.js';
import { createTestContext } from '../fixtures/test-context.js';
import type { HookInput } from '../../types.js';

function input(sid: string): HookInput {
  return {
    hook_event: 'PostToolUse',
    tool_name: 'Read',
    session_id: sid,
    tool_input: {},
  } as HookInput;
}

function writeChainState(projectDir: string, payload: Record<string, unknown>) {
  const dir = join(projectDir, '.claude', 'chain');
  mkdirSync(dir, { recursive: true });
  writeFileSync(join(dir, 'state.json'), JSON.stringify(payload));
}

describe('posttool/chain-staleness-checker (#1913)', () => {
  let projectDir: string;
  let eventsDir: string;
  let eventsPath: string;
  let prevEventsEnv: string | undefined;

  beforeEach(() => {
    projectDir = mkdtempSync(join(tmpdir(), 'ork-chain-stale-proj-'));
    eventsDir = mkdtempSync(join(tmpdir(), 'ork-chain-stale-events-'));
    eventsPath = join(eventsDir, 'events.jsonl');
    prevEventsEnv = process.env.ORK_EVENTS_LOG;
    process.env.ORK_EVENTS_LOG = eventsPath;
    chainInternals.lastCheck.clear();
  });

  afterEach(() => {
    chainInternals.lastCheck.clear();
    if (prevEventsEnv === undefined) delete process.env.ORK_EVENTS_LOG;
    else process.env.ORK_EVENTS_LOG = prevEventsEnv;
    rmSync(projectDir, { recursive: true, force: true });
    rmSync(eventsDir, { recursive: true, force: true });
  });

  it('returns silent success when chain state file is missing', () => {
    const ctx = createTestContext({ projectDir, sessionId: 'sid-1' });
    const res = chainStalenessChecker(input('sid-1'), ctx);
    expect(res).toEqual({ continue: true, suppressOutput: true });
    expect(existsSync(eventsPath)).toBe(false);
  });

  it('emits chain_stale when updated_at is older than threshold', () => {
    const staleAgoMs = chainInternals.STALE_THRESHOLD_MS + 60_000;
    const updatedAtIso = new Date(Date.now() - staleAgoMs).toISOString();
    writeChainState(projectDir, {
      chain_id: 'c-abc',
      phase: 'review',
      status: 'running',
      updated_at: updatedAtIso,
    });

    const ctx = createTestContext({ projectDir, sessionId: 'sid-stale' });
    const res = chainStalenessChecker(input('sid-stale'), ctx);
    expect(res).toEqual({ continue: true, suppressOutput: true });

    const events = readEventsSince(null);
    expect(events).toHaveLength(1);
    const ev = events[0];
    expect(ev.type).toBe('chain_stale');
    expect(ev.sid).toBe('sid-stale');
    if (ev.type === 'chain_stale') {
      expect(ev.chain_id).toBe('c-abc');
      expect(ev.phase).toBe('review');
      expect(ev.stale_for_ms).toBeGreaterThanOrEqual(
        chainInternals.STALE_THRESHOLD_MS,
      );
    }
  });

  it('does NOT emit when chain is fresh (updated_at within threshold)', () => {
    writeChainState(projectDir, {
      chain_id: 'c-fresh',
      phase: 'work',
      status: 'running',
      updated_at: new Date().toISOString(),
    });

    const ctx = createTestContext({ projectDir, sessionId: 'sid-fresh' });
    chainStalenessChecker(input('sid-fresh'), ctx);

    expect(existsSync(eventsPath)).toBe(false);
  });

  it('does NOT emit when status === "completed"', () => {
    const staleAgoMs = chainInternals.STALE_THRESHOLD_MS + 60_000;
    writeChainState(projectDir, {
      chain_id: 'c-done',
      phase: 'final',
      status: 'completed',
      updated_at: new Date(Date.now() - staleAgoMs).toISOString(),
    });

    const ctx = createTestContext({ projectDir, sessionId: 'sid-done' });
    chainStalenessChecker(input('sid-done'), ctx);

    expect(existsSync(eventsPath)).toBe(false);
  });

  it('rate-limits subsequent checks within the window per session', () => {
    const staleAgoMs = chainInternals.STALE_THRESHOLD_MS + 60_000;
    writeChainState(projectDir, {
      chain_id: 'c-rate',
      status: 'running',
      updated_at: new Date(Date.now() - staleAgoMs).toISOString(),
    });

    const ctx = createTestContext({ projectDir, sessionId: 'sid-rate' });
    chainStalenessChecker(input('sid-rate'), ctx);
    // Second call inside the rate-limit window: should be skipped.
    chainStalenessChecker(input('sid-rate'), ctx);

    const events = readEventsSince(null);
    expect(events).toHaveLength(1);
  });

  it('does not rate-limit across different sessions', () => {
    const staleAgoMs = chainInternals.STALE_THRESHOLD_MS + 60_000;
    writeChainState(projectDir, {
      chain_id: 'c-multi',
      status: 'running',
      updated_at: new Date(Date.now() - staleAgoMs).toISOString(),
    });

    const ctx1 = createTestContext({ projectDir, sessionId: 'sid-a' });
    const ctx2 = createTestContext({ projectDir, sessionId: 'sid-b' });
    chainStalenessChecker(input('sid-a'), ctx1);
    chainStalenessChecker(input('sid-b'), ctx2);

    const events = readEventsSince(null);
    expect(events).toHaveLength(2);
    expect(new Set(events.map(e => e.sid))).toEqual(new Set(['sid-a', 'sid-b']));
  });

  it('falls back to file mtime when updated_at is absent', () => {
    writeChainState(projectDir, { chain_id: 'c-mtime', status: 'running' });
    // Backdate the file mtime to before the threshold.
    const stalePast = (Date.now() - chainInternals.STALE_THRESHOLD_MS - 60_000) / 1000;
    utimesSync(
      join(projectDir, '.claude', 'chain', 'state.json'),
      stalePast,
      stalePast,
    );

    const ctx = createTestContext({ projectDir, sessionId: 'sid-mtime' });
    chainStalenessChecker(input('sid-mtime'), ctx);

    const events = readEventsSince(null);
    expect(events).toHaveLength(1);
    expect(events[0].type).toBe('chain_stale');
  });

  it('silent success when state.json is malformed', () => {
    const dir = join(projectDir, '.claude', 'chain');
    mkdirSync(dir, { recursive: true });
    writeFileSync(join(dir, 'state.json'), '{ not valid json');

    const ctx = createTestContext({ projectDir, sessionId: 'sid-bad' });
    const res = chainStalenessChecker(input('sid-bad'), ctx);
    expect(res).toEqual({ continue: true, suppressOutput: true });
    expect(existsSync(eventsPath)).toBe(false);
  });
});
